function autoFormatTime(N){let H=N['value']['replace'](/\D/g,'');switch(H['length']>0x4&&(H=H['slice'](0x0,0x4)),H['length']){case 0x0:case 0x1:case 0x2:N['value']=H;break;case 0x3:if(parseInt(H['slice'](0x0,0x2),0xa)<=0x17)N['value']=H['slice'](0x0,0x2)+':'+H['slice'](0x2);else{let n=H['slice'](0x0,0x1)['padStart'](0x2,'0'),p=H['slice'](0x1);N['value']=n+':'+p;}break;case 0x4:let M=H['slice'](0x0,0x2),h=H['slice'](0x2);N['value']=M+':'+h;}}function transformTimeValue(N){let H=N['trim']();if(/^\d{2}$/['test'](H))return H[0x0]['padStart'](0x2,'0')+':'+H[0x1]['padStart'](0x2,'0');if(/^\d{3,4}$/['test'](H))return 0x3===H['length']?parseInt(H['slice'](0x0,0x2),0xa)<=0x17?H['slice'](0x0,0x2)+':'+H['slice'](0x2):H['slice'](0x0,0x1)['padStart'](0x2,'0')+':'+H['slice'](0x1):H['slice'](0x0,0x2)+':'+H['slice'](0x2);if(H['includes'](':')){let [M,h]=H['split'](':');return h||(h='00'),M=M['padStart'](0x2,'0'),h=h['padStart'](0x2,'0'),M+':'+h;}return H;}